#pragma PERSISTENT(read_test)
uint8_t read_test[PAGE_SIZE] = {0};

void main_workload()
{
    for (uint32_t i = BLOCKS_PER_PLANE - 2; i < BLOCKS_PER_PLANE; ++i)
        erase_op(i << 6);

    uint16_t page_start = 65534;
    uint8_t *ptr = (uint8_t *)workload;

    for (uint32_t i = 0; i < ((sizeof(workload) + PAGE_SIZE - 1) / PAGE_SIZE); ++i, --page_start)
        write_op(page_start, 0, ptr + i * PAGE_SIZE, PAGE_SIZE);

    page_start = 65534;

    for (uint32_t i = 0, cnt = 0; i < ((sizeof(workload) + PAGE_SIZE - 1) / PAGE_SIZE); ++i, --page_start)
    {
        read_op(page_start, 0, read_test, PAGE_SIZE);
        int16_t *h = (int16_t*)read_test;
        for (uint32_t j = 0; j < 1024; ++j, ++h, ++cnt)
            if (*h != workload[cnt])
                SET_BREAKPOINT(BP_ERROR);
    }

    SET_BREAKPOINT(BP_FINISHED);
}

void setup_sample_rate_timer()
{
    Timer_B_initUpModeParam initUpParam = {0};
    initUpParam.clockSource = TIMER_B_CLOCKSOURCE_SMCLK;
    initUpParam.clockSourceDivider = TIMER_B_CLOCKSOURCE_DIVIDER_32;
    initUpParam.timerPeriod = (CS_getSMCLK() >> 5) / SAMPLE_RATE;
    initUpParam.timerInterruptEnable_TBIE = TIMER_B_TBIE_INTERRUPT_DISABLE;
    initUpParam.captureCompareInterruptEnable_CCR0_CCIE = TIMER_B_CCIE_CCR0_INTERRUPT_ENABLE;
    initUpParam.timerClear = TIMER_B_DO_CLEAR;
    initUpParam.startTimer = false;
    Timer_B_initUpMode(TIMER_B0_BASE, &initUpParam);
    Timer_B_clear(TIMER_B0_BASE);
    Timer_B_startCounter(TIMER_B0_BASE, TIMER_B_UP_MODE);
}

